const items = $input.all();
const oneDayAgo = new Date();
oneDayAgo.setHours(oneDayAgo.getHours() - 24);

const filtered = items.filter(function(item) {
  const d = new Date(item.json.isoDate || item.json.pubDate || item.json.updated || '');
  return !isNaN(d) && d >= oneDayAgo;
});

// Fallback: se nessun articolo nelle ultime 24h (weekend/festivi), prendi i piu recenti
const toProcess = filtered.length > 0 ? filtered : items.slice(0, 8);

return toProcess
  .sort(function(a, b) {
    return new Date(b.json.isoDate || b.json.pubDate || b.json.updated || 0)
         - new Date(a.json.isoDate || a.json.pubDate || a.json.updated || 0);
  })
  .slice(0, 15)
  .map(function(item) {
    var hostname;
    try { hostname = new URL(item.json.link).hostname; } catch(e) { hostname = ''; }
    var isGithub = hostname.includes('github.com');
    return {
      json: {
        titolo: item.json.title || '',
        link: item.json.link || '',
        fonte: isGithub ? 'GitHub' : hostname,
        tipo: isGithub ? 'Release' : 'Articolo',
        snippet: String(item.json.contentSnippet || item.json.content || item.json.summary || '').replace(/<[^>]*>/g, '').slice(0, 200)
      }
    };
  });

const items = $input.all();

const lista = items.map(function(item, i) {
  return (i + 1) + '. [' + item.json.tipo + ' · ' + item.json.fonte + '] ' + item.json.titolo
    + '\n   Link: ' + item.json.link
    + '\n   Snippet: ' + item.json.snippet;
}).join('\n\n');

const oggi = new Date().toLocaleDateString('it-IT', { weekday: 'long', day: 'numeric', month: 'long' });

const lines = [
  'Sei un assistente editoriale per un team italiano che lavora su Marketing e AI.',
  '',
  'Hai ' + items.length + ' aggiornamenti da fonti diverse delle ultime 24 ore (articoli e release GitHub).',
  'Seleziona i 5 piu interessanti e rilevanti per un team di marketing/tech.',
  'Il digest va in Slack: tieni i riassunti brevissimi (max 120 caratteri ciascuno).',
  '',
  'AGGIORNAMENTI DISPONIBILI:',
  lista,
  '',
  'Rispondi SOLO con JSON valido (nessun markdown, nessun testo extra):',
  '{',
  '  "intro": "Daily Digest ' + oggi + '",',
  '  "articoli": [',
  '    {',
  '      "tag": "<AI|Marketing|Business|Release|Tools>",',
  '      "titolo": "<titolo breve in italiano, max 60 caratteri>",',
  '      "riassunto": "<1-2 frasi concise, max 120 caratteri>",',
  '      "link": "<url originale>"',
  '    }',
  '  ]',
  '}'
].join('\n');

return [{ json: { _claude_body: {
  model: 'claude-sonnet-4-5',
  max_tokens: 1024,
  messages: [{ role: 'user', content: lines }]
} } }];

const text = $input.first().json.content[0].text.trim();

const m = text.match(/\{[\s\S]*\}/);
if (!m) throw new Error('Nessun JSON trovato: ' + text.slice(0, 200));

let d;
try { d = JSON.parse(m[0]); }
catch(e) { throw new Error('JSON non parsabile'); }

const emojis = {
  AI: ':robot_face:',
  Marketing: ':bar_chart:',
  Business: ':briefcase:',
  Release: ':package:',
  Tools: ':wrench:'
};

const articoliText = d.articoli.map(function(a) {
  const emoji = emojis[a.tag] || ':newspaper:';
  return emoji + ' *' + a.titolo + '*\n' + a.riassunto + '\n<' + a.link + '|Leggi →>';
}).join('\n\n');

const messaggio = ':newspaper: *' + d.intro + '*\n\n' + articoliText + '\n\n_Generato automaticamente · n8n + Claude_';

return [{ json: { testo: messaggio } }];
